styles:
.pricing-page {
      padding-top: 8rem;
      padding-bottom: 4rem;
      text-align: center;
      background: white;
    }
    .pricing-page h1 {
      font-size: clamp(2rem, 5vw, 3rem);
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .pricing-page .subtitle {
      color: var(--text-secondary);
      font-size: 1.125rem;
      margin-bottom: 0.5rem;
    }
    .pricing-badge {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      padding: 0.5rem 1rem;
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: 9999px;
      font-size: 0.875rem;
      color: var(--text-secondary);
      margin-top: 1rem;
    }
    .pricing-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 2rem;
      max-width: 800px;
      margin: 4rem auto 0;
    }
    .pricing-card {
      background: var(--bg-secondary);
      border: 2px solid var(--border);
      border-radius: var(--radius-xl);
      padding: 2.5rem;
      display: flex;
      flex-direction: column;
      transition: transform 0.2s, box-shadow 0.2s;
    }
    .pricing-card:hover {
      transform: translateY(-4px);
      box-shadow: 0 12px 40px rgba(0, 0, 0, 0.08);
    }
    .pricing-card.paid {
      border-color: var(--primary);
      position: relative;
    }
    .popular-badge {
      position: absolute;
      top: -12px;
      left: 50%;
      transform: translateX(-50%);
      background: var(--primary);
      color: white;
      padding: 0.25rem 1rem;
      border-radius: 9999px;
      font-size: 0.75rem;
      font-weight: 600;
    }
    .pricing-card h3 {
      font-size: 1.5rem;
      margin-bottom: 0.5rem;
      color: var(--text-primary);
    }
    .pricing-card .price {
      font-size: 3rem;
      font-weight: 700;
      color: var(--text-primary);
      margin-bottom: 0.5rem;
    }
    .pricing-card .price span {
      font-size: 1rem;
      font-weight: 400;
      color: var(--text-secondary);
    }
    .pricing-card .price-note {
      font-size: 0.875rem;
      color: var(--text-muted);
      margin-bottom: 1.5rem;
    }
    .pricing-features {
      flex: 1;
      margin-bottom: 2rem;
      text-align: left;
    }
    .pricing-features li {
      display: flex;
      align-items: center;
      gap: 0.75rem;
      padding: 0.75rem 0;
      color: var(--text-secondary);
      border-bottom: 1px solid var(--border);
      font-size: 0.9375rem;
    }
    .pricing-features li:last-child {
      border-bottom: none;
    }
    .pricing-features .check-icon {
      width: 20px;
      height: 20px;
      color: var(--success);
      flex-shrink: 0;
    }
    .pricing-features .coming-soon {
      color: var(--text-muted);
      font-style: italic;
    }
    .pricing-features .coming-soon .check-icon {
      color: var(--text-muted);
    }

    .comparison-section {
      padding: 5rem 0;
      background: var(--bg-secondary);
    }
    .comparison-section .section-header {
      text-align: center;
      margin-bottom: 3rem;
    }
    .comparison-section .section-header h2 {
      font-size: 2rem;
      margin-bottom: 0.75rem;
    }
    .comparison-section .section-header p {
      color: var(--text-secondary);
      max-width: 600px;
      margin: 0 auto;
    }

    .comparison-table-wrapper {
      overflow-x: auto;
      border-radius: var(--radius-lg);
      box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
      background: white;
    }
    .comparison-table {
      width: 100%;
      min-width: 800px;
      border-collapse: collapse;
      background: white;
    }
    .comparison-table thead {
      background: var(--bg-secondary);
    }
    .comparison-table th {
      padding: 1.25rem 1rem;
      text-align: center;
      font-weight: 600;
      font-size: 0.9375rem;
      border-bottom: 2px solid var(--border);
    }
    .comparison-table th:first-child {
      text-align: left;
      min-width: 200px;
    }
    .comparison-table th.highlight {
      background: linear-gradient(135deg, rgba(79, 70, 229, 0.1) 0%, rgba(139, 92, 246, 0.1) 100%);
      color: var(--primary);
    }
    .comparison-table td {
      padding: 1rem;
      text-align: center;
      border-bottom: 1px solid var(--border);
      font-size: 0.9375rem;
    }
    .comparison-table td:first-child {
      text-align: left;
      font-weight: 500;
      color: var(--text-primary);
    }
    .comparison-table tr:hover td {
      background: rgba(79, 70, 229, 0.03);
    }
    .comparison-table tr:last-child td {
      border-bottom: none;
    }
    .comparison-table td.highlight {
      background: linear-gradient(135deg, rgba(79, 70, 229, 0.05) 0%, rgba(139, 92, 246, 0.05) 100%);
    }
    .check {
      color: var(--success);
      font-weight: 700;
    }
    .cross {
      color: var(--text-muted);
    }
    .partial {
      color: #f59e0b;
      font-size: 0.8125rem;
    }
    .brand-logo {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      font-weight: 600;
    }
    .brand-logo img {
      width: 20px;
      height: 20px;
    }
    .highlight .brand-logo {
      color: var(--primary);
    }

    .savings-section {
      padding: 4rem 0;
      text-align: center;
      background: linear-gradient(135deg, var(--primary) 0%, var(--accent) 100%);
      color: white;
    }
    .savings-section h2 {
      font-size: 1.75rem;
      margin-bottom: 1rem;
      color: white;
    }
    .savings-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 2rem;
      max-width: 800px;
      margin: 2rem auto 0;
    }
    .savings-card {
      background: rgba(255, 255, 255, 0.15);
      border-radius: var(--radius-lg);
      padding: 1.5rem;
      backdrop-filter: blur(10px);
    }
    .savings-card .amount {
      font-size: 2.5rem;
      font-weight: 700;
      margin-bottom: 0.5rem;
    }
    .savings-card .desc {
      font-size: 0.9375rem;
      opacity: 0.9;
    }

    .cta-section {
      text-align: center;
      padding: 4rem 0;
      background: white;
    }
    .cta-section h2 {
      font-size: 2rem;
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .cta-section p {
      color: var(--text-secondary);
      max-width: 600px;
      margin: 0 auto 2rem;
      line-height: 1.6;
    }

    @media (max-width: 768px) {
      .pricing-page {
        padding: 6rem 0 3rem;
      }
      .pricing-grid {
        grid-template-columns: 1fr;
        margin-top: 3rem;
      }
      .savings-grid {
        grid-template-columns: 1fr;
        gap: 1rem;
      }
      .comparison-section {
        padding: 3rem 0;
      }
      .comparison-table th,
      .comparison-table td {
        padding: 0.75rem 0.5rem;
        font-size: 0.8125rem;
      }
    }

    @media (max-width: 576px) {
      .pricing-card {
        padding: 1.5rem;
      }
      .pricing-card .price {
        font-size: 2.5rem;
      }
      .cta-section h2 {
        font-size: 1.5rem;
      }
      .comparison-table th:first-child,
      .comparison-table td:first-child {
        min-width: 140px;
      }
    }
